func TestDecoder_DefaultValues_NestedStructWithNull(t *testing.T) {
	type Default struct {
		Key string `yaml:"key"`
	}

	type Test struct {
		First    string  `yaml:"first"`
		Defaults Default `yaml:"second"`
	}

	test := Test{Defaults: Default{Key: "My default Value"}}
	yml := `first: "Test"
second:
  # Just want to document the fields of the nested struct
#  key: "Value from YAML"
`
	d := yaml.NewDecoder(strings.NewReader(yml))
	err := d.Decode(&test)
	if err != nil {
		t.Fatalf("parsing should succeed: %s", err)
	}

	if test.First != "Test" {
		t.Fatalf("test.First should be 'Test', got '%s'", test.First)
	}

	if test.Defaults.Key != "My default Value" {
		t.Fatalf("test.Defaults.Key should be 'My default Value', got '%s'", test.Defaults.Key)
	}
}

func TestDecoder_DefaultValues_NestedPointerStructWithNull(t *testing.T) {
	type Default struct {
		Key string `yaml:"key"`
	}

	type Test struct {
		First    string   `yaml:"first"`
		Defaults *Default `yaml:"second"`
	}

	defaultPtr := &Default{Key: "My default Value"}
	test := Test{Defaults: defaultPtr}
	yml := `first: "Test"
second:
  # Just want to document the fields of the nested struct
#  key: "Value from YAML"
`
	d := yaml.NewDecoder(strings.NewReader(yml))
	err := d.Decode(&test)
	if err != nil {
		t.Fatalf("parsing should succeed: %s", err)
	}

	if test.First != "Test" {
		t.Fatalf("test.First should be 'Test', got '%s'", test.First)
	}

	if test.Defaults == nil {
		t.Fatalf("test.Defaults should not be nil")
	}

	if test.Defaults.Key != "My default Value" {
		t.Fatalf("test.Defaults.Key should be 'My default Value', got '%s'", test.Defaults.Key)
	}
}

